import json,boto3,urllib.request
def send(e,c,s,pid,rd={},r=''):
  b=json.dumps({'Status':s,'Reason':r,'PhysicalResourceId':pid,'StackId':e['StackId'],'RequestId':e['RequestId'],'LogicalResourceId':e['LogicalResourceId'],'Data':rd}).encode()
  urllib.request.urlopen(urllib.request.Request(e['ResponseURL'],data=b,method='PUT'))
def handler(e,c):
  pid=e.get('PhysicalResourceId',c.log_stream_name)
  try:
    p=e['ResourceProperties']
    token=p['Token'];role_arn=p['RoleArn'];sqs_arn=p['SqsArn'];stack_region=p['StackRegion']
    sqs_region=sqs_arn.split(':')[3];account_id=e['StackId'].split(':')[4]
    rule_name='nudgebee-multi-region-'+token[:8];pid=rule_name
    pattern=json.dumps({'source':['aws.ec2','aws.rds','aws.ecs','aws.lambda','aws.cloudwatch'],'detail-type':['EC2 Instance State-change Notification','RDS DB Instance Event','ECS Task State Change','ECS Service Action','AWS API Call via CloudTrail','CloudWatch Alarm State Change']})
    tpl=json.dumps({'nudgebeeAccountToken':token,'source':'<source>','detail-type':'<detail-type>','detail':'__DETAIL__','account':'<account>','region':'<region>','time':'<time>','resources':'__RESOURCES__'}).replace('"__DETAIL__"','<detail>').replace('"__RESOURCES__"','<resources>')
    ip={'source':'$.source','detail-type':'$.detail-type','detail':'$.detail','account':'$.account','region':'$.region','time':'$.time','resources':'$.resources'}
    regions=[r['RegionName'] for r in boto3.client('ec2',region_name=stack_region).describe_regions(Filters=[{'Name':'opt-in-status','Values':['opt-in-not-required','opted-in']}])['Regions']]
    ok=0;fail=0
    if e['RequestType'] in ('Create','Update'):
      for rg in regions:
        try:
          eb=boto3.client('events',region_name=rg)
          eb.put_rule(Name=rule_name,EventPattern=pattern,State='ENABLED',Description='Nudgebee multi-region passthrough')
          if rg==sqs_region:
            eb.put_targets(Rule=rule_name,Targets=[{'Id':'NudgebeeSQS','Arn':sqs_arn,'RoleArn':role_arn,'InputTransformer':{'InputPathsMap':ip,'InputTemplate':tpl}}])
          else:
            eb.put_targets(Rule=rule_name,Targets=[{'Id':'NudgebeeSQS','Arn':'arn:aws:events:'+sqs_region+':'+account_id+':event-bus/default','RoleArn':role_arn}])
          ok+=1
        except Exception as x:
          print(f'WARN {rg}: {x}');fail+=1
    elif e['RequestType']=='Delete':
      old_pid=e.get('PhysicalResourceId','')
      if old_pid!=rule_name:
        print(f'SKIP delete: CF cleanup of old resource {old_pid}')
      else:
        for rg in regions:
          try:
            eb=boto3.client('events',region_name=rg)
            try:
              eb.remove_targets(Rule=rule_name,Ids=['NudgebeeSQS'])
            except:pass
            try:
              eb.delete_rule(Name=rule_name)
            except:pass
            ok+=1
          except Exception as x:
            print(f'WARN delete {rg}: {x}');fail+=1
    send(e,c,'SUCCESS',pid,{'RegionsOk':str(ok),'RegionsFailed':str(fail)})
  except Exception as x:
    print(f'ERROR: {x}');send(e,c,'FAILED',pid,r=str(x))
